// 获取爬虫返回的所有数据
const items = $input.all();
const uniqueItems = [];
const seenUrls = new Set();

for (const item of items) {
    const url = item.json.url;
    if (url && !seenUrls.has(url)) {
        seenUrls.add(url);
        uniqueItems.push(item);
    }
}

return uniqueItems;

try {
    // 1. 首先检查是否有 HTTP 错误（由 Continue on Fail 产生）
    // 或者检查 LLM 是否因为安全策略返回了空结果
    if ($json.error || !$json.choices || $json.choices.length === 0) {
        throw new Error("API_ERROR_OR_SENSITIVE_CONTENT");
    }

    const rawContent = $json.choices[0].message.content;

    // 2. 去除 Markdown 标记
    const cleanJson = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsedData = JSON.parse(cleanJson);

    return {
        json: {
            title: parsedData.title || "无标题",
            // 回退到 Loop 节点的原始 URL，确保链路完整
            url: parsedData.url || $node["Loop Over Items"].json.url, 
            tag: parsedData.tag || "未分类",
            importance_score: parsedData.importance_score || 5,
            content: parsedData.content || "摘要生成失败",
            source: parsedData.source || "未知来源",
            status: "success" // 正常分析成功
        }
    };

} catch (error) {
    // 3. 捕获所有异常：包含 API 报错、敏感词拦截、JSON 解析失败
    return {
        json: {
            status: "skip", // 标记为跳过
            error_type: error.message,
            // 尽量保留原始信息以便排查
            title: $node["Loop Over Items"].json.title || "分析失败条目",
            url: $node["Loop Over Items"].json.url,
            content: "该条内容因政策或技术原因无法分析"
        }
    };
}

// 遍历每一个 Item 进行处理
for (const item of $input.all()) {
  if (item.json.content) {
    // 1. 去除换行符 \n 和回车符 \r
    // 2. 将多个连续空格替换为一个空格
    // 3. 去除首尾空白字符
    item.json.content = item.json.content
      .replace(/[\r\n]+/g, ' ')  // 将所有换行替换为单个空格
      .replace(/\s+/g, ' ')      // 将多个空格/制表符替换为单空格
      .trim();                   // 去除首尾空格
  }

  if (item.json.title) {
    item.json.title = item.json.title
      .replace(/[\r\n]+/g, '')   // 标题通常不需要换行，直接去掉
      .trim();
  }
}

return $input.all();

